// Parse Google Trends response and extract trending topics
const rawData = $input.first().json.data || $input.first().json.body || '';
let trendsText = typeof rawData === 'string' ? rawData : JSON.stringify(rawData);

// Google Trends API returns with a prefix that needs removal
if (trendsText.startsWith(')]}')) {
  trendsText = trendsText.substring(5);
}

let trendingTopics = [];

try {
  const parsed = JSON.parse(trendsText);
  const dailyTrends = parsed?.default?.trendingSearchesDays || [];

  for (const day of dailyTrends) {
    for (const trend of (day.trendingSearches || [])) {
      trendingTopics.push({
        title: trend.title?.query || '',
        traffic: trend.formattedTraffic || '',
        relatedQueries: (trend.relatedQueries || []).map(q => q.query).join(', '),
        source: trend.articles?.[0]?.source || '',
        snippet: trend.articles?.[0]?.snippet || '',
        imageUrl: trend.image?.imageUrl || ''
      });
    }
  }
} catch (e) {
  // Fallback: use raw text as context for AI
  trendingTopics = [{ title: 'General trending topics', rawContext: trendsText.substring(0, 2000) }];
}

// Take top 5 trending topics
const topTrends = trendingTopics.slice(0, 5);

return [{ json: { trends: topTrends, fetchedAt: new Date().toISOString() } }];

