// Parse the AI analysis response
const response = $input.first().json;
let analysisText = '';

if (response.choices && response.choices[0]) {
  analysisText = response.choices[0].message?.content || '';
} else if (response.body) {
  analysisText = typeof response.body === 'string' ? response.body : JSON.stringify(response.body);
}

let analysis = {};

try {
  // Extract JSON from the response
  const jsonMatch = analysisText.match(/\{[\s\S]*\}/);
  if (jsonMatch) {
    analysis = JSON.parse(jsonMatch[0]);
  }
} catch (e) {
  analysis = {
    selected_topic: 'AI Innovation in Daily Life',
    why_trending: 'AI tools becoming mainstream in everyday tasks',
    target_audience: 'Tech-savvy professionals and entrepreneurs',
    campaign_angle: 'How AI simplifies your daily workflow',
    hashtags: ['#AILife', '#TechTrends', '#Innovation', '#FutureOfWork', '#SmartLiving', '#AITools', '#ProductivityHacks', '#DigitalTransformation', '#TechInnovation', '#Trending'],
    mood_keywords: ['futuristic', 'vibrant', 'clean', 'inspiring', 'dynamic']
  };
}

return [{
  json: {
    ...analysis,
    timestamp: new Date().toISOString()
  }
}];

