// Parse the generated content
const response = $input.first().json;
let contentText = '';

if (response.choices && response.choices[0]) {
  contentText = response.choices[0].message?.content || '';
} else if (response.message?.content) {
  contentText = response.message.content;
}

let content = {};
try {
  const jsonMatch = contentText.match(/\{[\s\S]*\}/);
  if (jsonMatch) {
    content = JSON.parse(jsonMatch[0]);
  }
} catch (e) {
  content = {
    linkedin_post: contentText,
    instagram_caption: contentText.substring(0, 500),
    facebook_post: contentText.substring(0, 600),
    pinterest_description: contentText.substring(0, 300),
    poster_prompt: 'A modern, professional social media campaign poster with bold typography, gradient background in blue and purple tones, featuring abstract geometric shapes and clean design elements.'
  };
}

return [{ json: content }];

// Extract poster URL and prepare for upload
const posterData = $input.first().json;
let imageUrl = '';

if (posterData.data && posterData.data[0]) {
  imageUrl = posterData.data[0].url || '';
} else if (posterData.url) {
  imageUrl = posterData.url;
}

// Get content from previous node
const content = $('Parse Generated Content').first().json;

return [{
  json: {
    imageUrl: imageUrl,
    linkedin_post: content.linkedin_post || '',
    instagram_caption: content.instagram_caption || '',
    facebook_post: content.facebook_post || '',
    pinterest_description: content.pinterest_description || '',
    poster_prompt: content.poster_prompt || '',
    generatedAt: new Date().toISOString()
  }
}];

// Prepare hosted image URL for all platforms
const imgbbResponse = $input.first().json;
const hostedImageUrl = imgbbResponse?.data?.url || imgbbResponse?.data?.display_url || $('Prepare Poster & Content').first().json.imageUrl;
const content = $('Prepare Poster & Content').first().json;

return [{
  json: {
    imageUrl: hostedImageUrl,
    linkedin_post: content.linkedin_post,
    instagram_caption: content.instagram_caption,
    facebook_post: content.facebook_post,
    pinterest_description: content.pinterest_description,
    generatedAt: content.generatedAt
  }
}];

